{{
  (() => {
    const rawData = fetch_recipes.data?.items || fetch_recipes.data || [];
    if (rawData.length === 0) return [{ label: "❌ Mac Offline", value: "none" }];

    // Strip "Tier " prefix if it exists, leaving just the number
    const targetTier = String(select_tier.selectedOptionValue).replace(/\D/g, "");
    const currentUser = appsmith.store.currentUser || {};
    const playerTier = Number(currentUser.Tier || 0);

    const filtered = rawData.filter(r => {
      // 1. Tier Match (Loose equality to handle string vs number)
      if (Number(r.Tier) !== Number(targetTier)) return false;

      // 2. Rank Unlock: Tier 2 players always see Tier 1
      if (playerTier > Number(targetTier)) return true;

      // 3. Completion Check: Make everything uppercase to avoid case issues
      const completionField = `T${targetTier}_Completion`;
      const completionStr = String(currentUser[completionField] || "").toUpperCase();
      const recipeCode = String(r.recipe_code || "").toUpperCase();

      return completionStr.includes(recipeCode);
    });

    if (filtered.length === 0) {
      return [{ label: "🚫 No Unlocked Recipes Found", value: "none" }];
    }

    return filtered.map(r => ({ label: r.Name, value: r.id }));
  })()
}}
